solutions.python:
import sys

class Solution:
    def isValid(self, queue:
        list[int]) -> bool:
        return len(queue) == 0

    def dequeue(self, queue:
        list[int]) -> int:
        if len(queue) == 0:
            raise ValueError("Queue is empty")
        return queue.pop(0)

def main():
    solution = Solution()
    queue = list(map(int, input().split()))
    print(solution.dequeue(queue))

if __name__ == "__main__":
    main()

solutions.cpp:
#include <iostream>
#include <vector>

using namespace std;

class Solution {
public:
    bool isValid(vector<char> queue) {
        return queue.empty();
    }

    int dequeue(vector<char>& queue) {
        if (queue.empty()) {
            throw runtime_error("Queue is empty");
        }
        return queue.front();
    }
};

tint main() {
    Solution solution;
    vector<char> queue;
    for (char c : input()) {
        queue.push_back(c);
    }
    try {
        cout << solution.dequeue(queue) << endl;
    } catch (const exception& e) {
        cout << e.what() << endl;
    }
    return 0;
}
